/// Convenience wrapper for IoT Device operations
class IoTDeviceService {
  final HttpService _httpService;

  IoTDeviceService(this._httpService);

  /// Update the target device IP address
  void setDeviceAddress(String ipAddress, {int port = 80}) {
    _httpService.updateIotDeviceUrl(ipAddress, port: port);
  }

  Future<dynamic> get(String path,
          {Map<String, String>? queryParams, Map<String, String>? headers}) =>
      _httpService.get(ServiceTarget.iotDevice, path,
          queryParams: queryParams, headers: headers);

  Future<dynamic> post(String path,
          {dynamic body,
          Map<String, String>? queryParams,
          Map<String, String>? headers}) =>
      _httpService.post(ServiceTarget.iotDevice, path,
          body: body, queryParams: queryParams, headers: headers);

  Future<dynamic> put(String path,
          {dynamic body,
          Map<String, String>? queryParams,
          Map<String, String>? headers}) =>
      _httpService.put(ServiceTarget.iotDevice, path,
          body: body, queryParams: queryParams, headers: headers);

  Future<dynamic> delete(String path,
          {Map<String, String>? queryParams, Map<String, String>? headers}) =>
      _httpService.delete(ServiceTarget.iotDevice, path,
          queryParams: queryParams, headers: headers);

  /// Get device status/info
  Future<Map<String, dynamic>> getDeviceStatus() async {
    final response = await get('/status');
    return response is Map<String, dynamic> ? response : {};
  }

  /// Send a command to the IoT device
  Future<dynamic> sendCommand(String command,
      {Map<String, dynamic>? params}) async {
    return await post('/command', body: {
      'command': command,
      if (params != null) 'params': params,
    });
  }

  /// Update device configuration
  Future<dynamic> updateConfig(Map<String, dynamic> config) async {
    return await put('/config', body: config);
  }

  /// Get sensor data from device
  Future<Map<String, dynamic>> getSensorData() async {
    final response = await get('/sensors');
    return response is Map<String, dynamic> ? response : {};
  }

  /// Ping device to check connectivity
  Future<bool> ping() async {
    try {
      await get('/ping');
      return true;
    } catch (_) {
      return false;
    }
  }

  /// Discover IoT devices on the local network
  static Future<List<String>> discoverDevices({
    String subnet = '192.168.1',
    int port = 80,
    Duration timeout = const Duration(seconds: 2),
  }) async {
    final discoveredDevices = <String>[];
    final futures = <Future>[];

    for (int i = 1; i <= 254; i++) {
      final ip = '$subnet.$i';
      futures.add(
        Future(() async {
          try {
            final client = http.Client();
            try {
              final response = await client
                  .get(Uri.parse('http://$ip:$port/ping'))
                  .timeout(timeout);
              if (response.statusCode == 200) {
                discoveredDevices.add(ip);
              }
            } finally {
              client.close();
            }
          } catch (_) {
            // Device not found or not responding
          }
        }),
      );
    }

    await Future.wait(futures);
    return discoveredDevices;
  }
}

// Fix the TimeoutException import conflict by using dart:async with prefix
import 'dart:async' as dart_async;

/// Example usage and main entry point
void main() async {
  // Initialize the HTTP service
  final httpService = HttpService(
    cloudConfig: const ServiceConfig(
      baseUrl: 'https://api.example.com',
      timeout: Duration(seconds: 30),
      defaultHeaders: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      maxRetries: 3,
    ),
    iotConfig: const ServiceConfig(
      baseUrl: 'http://192.168.1.100',
      timeout: Duration(seconds: 10),
      defaultHeaders: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      maxRetries: 1,
    ),
  );

  // Create convenience service wrappers
  final cloudApi = CloudApiService(httpService);
  final iotDevice = IoTDeviceService(httpService);

  try {
    // --- Cloud API Examples ---

    // Login
    print('Logging in to cloud API...');
    final loginResponse = await cloudApi.login('user@example.com', 'password');
    print('Login response: $loginResponse');

    // Get devices list
    print('Fetching registered devices...');
    final devices = await cloudApi.getDevices();
    print('Devices: $devices');

    // Register a new device
    print('Registering new device...');
    final newDevice = await cloudApi.registerDevice({
      'name': 'Living Room Sensor',
      'type': 'temperature_humidity',
      'ip': '192.168.1.100',
    });
    print('New device: $newDevice');

    // --- IoT Device Examples ---

    // Set device address
    iotDevice.setDeviceAddress('192.168.1.100', port: 80);

    // Check device connectivity
    print('Pinging IoT device...');
    final isOnline = await iotDevice.ping();
    print('Device online: $isOnline');

    if (isOnline) {
      // Get device status
      print('Getting device status...');
      final status = await iotDevice.getDeviceStatus();
      print('Device status: $status');

      // Get sensor data
      print('Reading sensor data...');
      final sensorData = await iotDevice.getSensorData();
      print('Sensor data: $sensorData');

      // Send command
      print('Sending command to device...');
      final commandResult = await iotDevice.sendCommand('set_led', params: {
        'color': 'blue',
        'brightness': 80,
      });
      print('Command result: $commandResult');

      // Update config
      print('Updating device configuration...');
      final configResult = await iotDevice.updateConfig({
        'reporting_interval': 30,
        'unit': 'celsius',
      });
      print('Config update result: $configResult');
    }

    // --- Device Discovery ---
    print('Discovering devices on local network...');
    final discoveredIps = await IoTDeviceService.discoverDevices(
      subnet: '192.168.1',
      port: 80,
      timeout: const Duration(seconds: 2),
    );
    print('Discovered devices: $discoveredIps');
  } on ApiException catch (e) {
    print('API Error: ${e.message} (Status: ${e.statusCode})');
    if (e.responseBody != null) {
      print('Response body: ${e.responseBody}');
    }
  } on NetworkException catch (e) {
    print('Network Error: ${e.message}');
    if (e.url != null) {
      print('URL: ${e.url}');
    }
  } on TimeoutException catch (e) {
    print('Timeout Error: ${e.message}');
  } catch (e) {
    print('Unexpected error: $e');
  } finally {
    // Clean up
    httpService.dispose();
  }
}